#!/usr/bin/env php
<?php

$mainDir = sprintf('%s/main', dirname(__DIR__, 2));
$outputFile = sprintf('%s/gdb_inlined_script.c', $mainDir);

printf("Generating %s\n", $outputFile);

$gdbscript = file_get_contents(sprintf("%s/php_gdb.gdb", __DIR__));
$pyscript = file_get_contents(sprintf("%s/php_gdb.py", __DIR__));

// We can not inline gdb scripts, so let's embed the gdb script in the python
// one instead.
$pyscript = sprintf(
    "gdb.execute('''\n%s\n''')\n%s",
    addcslashes($gdbscript, '\'\\'),
    $pyscript,
);

$ccode = sprintf(
    <<<'C'
    /* Generated by %s */
    asm(
        ".pushsection \".debug_gdb_scripts\", \"MS\",@progbits,1\n"
        ".byte 4 /* Python Text */\n"
        ".ascii \"gdb.inlined-script\\n\"\n"
        %s
        ".byte 0\n"
        ".popsection\n"
    );
    C,
    basename(__FILE__),
    implode("\n    ", array_map(function ($line) {
        $escapedPy = addcslashes($line."\n", "\"\n\\");
        $escapedAsm = addcslashes(sprintf(".ascii \"%s\"\n", $escapedPy), "\"\n\\");
        return sprintf('"%s"', $escapedAsm);
    }, explode("\n", $pyscript))),
);

$len = file_put_contents($outputFile, $ccode);

if ($len !== strlen($ccode)) {
    printf("Failed\n");
    exit(1);
}
